   167→      tempObject.position.set(x, y, z);
   168→      tempObject.scale.set(width, height, 1);
   169→      tempObject.updateMatrix();
   170→      mesh.setMatrixAt(i, tempObject.matrix);
   171→
   172→      // Set color: selected gets distinct color, focused gets focus color, hovered gets brightened, normal is base
   173→      if (isSelected) {
   174→        tempColor.set(SELECTION_COLOR);
   175→        mesh.setColorAt(i, tempColor);
   176→      } else if (isFocused) {
   177→        // Focus uses a distinct purple color to differentiate from selection and hover
   178→        tempColor.set(FOCUS_COLOR);
   179→        mesh.setColorAt(i, tempColor);
   180→      } else if (isHovered) {
   181→        const baseColor = task.hasConflict ? CONFLICT_COLOR : COLORS[task.color];
   182→        const brightened = brightenColor(baseColor, HOVER_BRIGHTNESS);
   183→        mesh.setColorAt(i, brightened);
   184→      } else {
   185→        const baseColor = task.hasConflict ? CONFLICT_COLOR : COLORS[task.color];
   186→        tempColor.set(baseColor);
   187→        mesh.setColorAt(i, tempColor);
   188→      }
   189→    });
   190→
   191→    // Mark buffers for update
   192→    mesh.instanceMatrix.needsUpdate = true;
   193→    if (mesh.instanceColor) {
   194→      mesh.instanceColor.needsUpdate = true;
   195→    }
   196→  }, [tasks, tempObject, tempColor, hoveredTaskId, selectedTaskId, focusedTaskId]);
   197→
   198→  if (tasks.length === 0) {
   199→    return null;
   200→  }
   201→
   202→  return (
   203→    <instancedMesh
   204→      ref={meshRef}
   205→      args={[undefined, undefined, tasks.length]}
   206→    >
   207→      {/* Unit plane centered at origin - will be scaled by instance matrix */}
   208→      <planeGeometry args={[1, 1]} />
   209→      <meshBasicMaterial toneMapped={false} transparent={opacity < 1} opacity={opacity} />
   210→    </instancedMesh>
   211→  );
   212→}
   213→
   214→/**
   215→ * Conflict glow effect layer
   216→ * Renders a subtle glow behind conflict tasks
   217→ */
   218→function ConflictGlows({ tasks, opacity = 1 }: { tasks: TaskRender[]; opacity?: number }) {
   219→  const conflictTasks = useMemo(
   220→    () => tasks.filter((t) => t.hasConflict),
   221→    [tasks]
   222→  );
   223→
   224→  const meshRef = useRef<InstancedMesh>(null);
   225→  const tempObject = useMemo(() => new Object3D(), []);
   226→
   227→  useEffect(() => {
   228→    if (!meshRef.current || conflictTasks.length === 0) return;
   229→
   230→    const mesh = meshRef.current;
   231→
   232→    conflictTasks.forEach((task, i) => {
   233→      const width = task.duration * pxPerDay + 6; // Slightly larger for glow
   234→      const height = TASK_HEIGHT + 6;
   235→      const x = task.startDay * pxPerDay + (task.duration * pxPerDay) / 2;
   236→      const y = -task.trainIndex * pxPerTrain - pxPerTrain / 2;
   237→      const z = -0.05; // Behind the task block
   238→
   239→      tempObject.position.set(x, y, z);
   240→      tempObject.scale.set(width, height, 1);
   241→      tempObject.updateMatrix();
   242→      mesh.setMatrixAt(i, tempObject.matrix);
   243→    });
   244→
   245→    mesh.instanceMatrix.needsUpdate = true;
   246→  }, [conflictTasks, tempObject]);
   247→
   248→  if (conflictTasks.length === 0) {
   249→    return null;
   250→  }
   251→
   252→  return (
   253→    <instancedMesh
   254→      ref={meshRef}
   255→      args={[undefined, undefined, conflictTasks.length]}
   256→    >
   257→      <planeGeometry args={[1, 1]} />
   258→      <meshBasicMaterial
   259→        color={CONFLICT_COLOR}
   260→        transparent
   261→        opacity={0.3 * opacity}
   262→      />
   263→    </instancedMesh>
   264→  );
   265→}
   266→
   267→/**
   268→ * Focus ring effect layer (F021)
   269→ * Renders a pulsing ring around the focused task for accessibility
   270→ */
   271→function FocusRing({
   272→  tasks,
   273→  focusedTaskId,
   274→  opacity = 1,
   275→}: {
   276→  tasks: TaskRender[];
   277→  focusedTaskId: string | null;
   278→  opacity?: number;
   279→}) {
   280→  const focusedTask = useMemo(
   281→    () => (focusedTaskId ? tasks.find((t) => t.id === focusedTaskId) : null),
   282→    [tasks, focusedTaskId]
   283→  );
   284→
   285→  const meshRef = useRef<InstancedMesh>(null);
   286→  const tempObject = useMemo(() => new Object3D(), []);
   287→
   288→  useEffect(() => {
   289→    if (!meshRef.current) return;
   290→
   291→    const mesh = meshRef.current;
   292→
   293→    if (focusedTask) {
   294→      const width = focusedTask.duration * pxPerDay + 8; // Larger for ring effect
   295→      const height = TASK_HEIGHT + 8;
   296→      const x = focusedTask.startDay * pxPerDay + (focusedTask.duration * pxPerDay) / 2;
   297→      const y = -focusedTask.trainIndex * pxPerTrain - pxPerTrain / 2;
   298→      const z = 0.12; // Between focus and conflict glows
   299→
   300→      tempObject.position.set(x, y, z);
   301→      tempObject.scale.set(width, height, 1);
   302→      tempObject.updateMatrix();
   303→      mesh.setMatrixAt(0, tempObject.matrix);
   304→    } else {
   305→      // Hide the ring by scaling to zero
   306→      tempObject.scale.set(0, 0, 1);
   307→      tempObject.updateMatrix();
   308→      mesh.setMatrixAt(0, tempObject.matrix);
   309→    }
   310→
   311→    mesh.instanceMatrix.needsUpdate = true;
   312→  }, [focusedTask, tempObject]);
   313→
   314→  return (
   315→    <instancedMesh ref={meshRef} args={[undefined, undefined, 1]}>
   316→      <planeGeometry args={[1, 1]} />
   317→      <meshBasicMaterial
   318→        color={FOCUS_COLOR}
   319→        transparent
   320→        opacity={0.4 * opacity}
   321→      />
   322→    </instancedMesh>
   323→  );
   324→}
   325→
   326→/**
   327→ * MesoLayer Component
   328→ *
   329→ * Renders the DNA-like task block visualization for the MESO LOD level.
   330→ */
   331→export function MesoLayer({
   332→  tasks,
   333→  trainCount,
   334→  opacity = 1,
   335→  viewportBounds,
   336→  spatialIndex,
   337→  hoveredTaskId,
   338→  selectedTaskId,
   339→  focusedTaskId,
   340→}: MesoLayerProps) {
   341→  // TODO PERF-002: Use viewportBounds + spatialIndex for viewport culling
   342→  // For now, these props are accepted but not yet used for culling.
   343→  // Full culling implementation will be done in STATE-ARCH-001.Phase2
   344→  // when RBush spatial index replaces SimpleSpatialIndex.
   345→  // Calculate total days for row backgrounds
   346→  const totalDays = useMemo(() => {
   347→    if (tasks.length === 0) return 365 * 10; // Default: 10 years
   348→    const maxDay = Math.max(...tasks.map((t) => t.startDay + t.duration));
   349→    return Math.max(maxDay + 30, 365 * 10); // Add padding
   350→  }, [tasks]);
   351→
   352→  return (
   353→    <group>
   354→      {/* Row backgrounds (behind everything) */}
   355→      <RowBackgrounds trainCount={trainCount} totalDays={totalDays} opacity={opacity} />
   356→
   357→      {/* Conflict glow effects (behind task blocks) */}
   358→      <ConflictGlows tasks={tasks} opacity={opacity} />
   359→
   360→      {/* Focus ring effect (F021 - behind focused task block) */}
   361→      <FocusRing tasks={tasks} focusedTaskId={focusedTaskId ?? null} opacity={opacity} />
   362→
   363→      {/* Main task blocks */}
   364→      <TaskBlocks
   365→        tasks={tasks}
   366→        opacity={opacity}
   367→        hoveredTaskId={hoveredTaskId}
   368→        selectedTaskId={selectedTaskId}
   369→        focusedTaskId={focusedTaskId}
   370→      />
   371→    </group>
   372→  );
   373→}
